#include<iostream>#include<vector>#include<algorithm>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){               ll n,m,d;       cin>>n>>m>>d;       ll no_of_boxes_in_each_tower=0;       //max_weightof_a box=m;       //max_weightof_tower=d;       if(n*m<=d){        cout<<1<<"\n";       }       else{        no_of_boxes_in_each_tower=d/m + 1;        ll no_of_towers=(n+no_of_boxes_in_each_tower-1)/no_of_boxes_in_each_tower;        cout<<no_of_towers<<"\n";       }    }}